module RefModule (
    input clk,
    input nreset,
    input load,
    input [7:0] data,
    output [7:0] q );reg [7:0] q_reg;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or negedge nreset or posedge dbg_halt) begin
    if (!nreset)
        q_reg <= 8'b00000000;
    else if (load)
        q_reg <= data;
end

assign q = q_reg;

endmodule
